const $=id=>document.getElementById(id),num=v=>Number(v)||0,money=v=>'S/ '+num(v).toFixed(2),uid=()=>crypto.randomUUID?.()||Date.now()+'_'+Math.random().toString(36).slice(2),today=()=>new Date().toISOString().slice(0,10),norm=s=>String(s||'').normalize('NFD').replace(/[\u0300-\u036f]/g,'').toLowerCase().trim();
const defaults={shopping:[],tasks:[],expenses:[],notes:[],pantry:[],events:[],fixedExpenses:[],extraIncomes:[],customCatalog:[],favorites:[],priceHistory:[],notifications:[],activity:[],notificationPrefs:{enabled:true,market:true,pantry:true,finance:true,agenda:true,shared:true,dailySummary:false,dailySummaryTime:'08:00'},notificationMeta:{},budget:300,preferredStore:'market',theme:'light',salaryPayments:[{id:'q1',name:'Quincena',amount:500,day:15,active:true},{id:'q2',name:'Fin de mes',amount:900,day:31,active:true}]};
let state=structuredClone(defaults),user=null,householdId='',inviteCode='',unsub=null,saveTimer=null,remote=false,currentView='home',marketFilter='pending',pantryFilter='all',marketSearch='';
function migrate(v={}){const x={...structuredClone(defaults),...v};for(const k of ['shopping','tasks','expenses','notes','pantry','events','fixedExpenses','extraIncomes','customCatalog','favorites','priceHistory','notifications','activity'])if(!Array.isArray(x[k]))x[k]=[];x.notificationPrefs={...defaults.notificationPrefs,...(x.notificationPrefs||{})};x.notificationMeta={...(x.notificationMeta||{})};return x}
