function stateRef(){return doc(db,'households',householdId,'appState','main')}async function push(){try{sync('saving');await setDoc(stateRef(),{state,updatedAt:serverTimestamp(),updatedBy:user.uid,version:VERSION},{merge:true});sync('ok')}catch(e){console.error(e);sync('error')}}
function sync(mode){$('syncDot').style.background=mode==='error'?'var(--red)':mode==='saving'?'var(--orange)':'var(--green)'}
function toast(t){const e=$('toast');e.textContent=t;e.classList.add('show');clearTimeout(e.t);e.t=setTimeout(()=>e.classList.remove('show'),2200)}
function actor(){return user?.displayName||user?.email?.split('@')[0]||'Alguien'}
function prefs(){return {...defaults.notificationPrefs,...(state.notificationPrefs||{})}}
function unreadNotifications(){return state.notifications.filter(n=>!(n.readBy||[]).includes(user?.uid||'local')).length}
