async function requestNotifications(){
  if(!('Notification'in window))return toast('Este navegador no admite avisos del sistema');
  if(!isStandalone())return toast('En iPhone, instala la app en la pantalla de inicio para activar avisos');
  try{const permission=await Notification.requestPermission();toast(permission==='granted'?'Avisos del sistema activados':'Permiso no concedido; los avisos internos seguirán funcionando');render()}catch(e){console.warn(e);toast('No se pudo solicitar el permiso; la app continúa funcionando normalmente')}
}
function eventDateTime(e){if(!e.date)return null;const t=e.time||'09:00';const d=new Date(`${e.date}T${t}:00`);return Number.isNaN(d.getTime())?null:d}
function checkAgendaReminders(){
  if(!prefs().enabled||prefs().agenda===false)return;const now=Date.now();let changed=false;
  for(const e of state.events){const dt=eventDateTime(e);if(!dt)continue;const mins=num(e.reminderMinutes??60),trigger=dt.getTime()-mins*60000,key=`${e.id}:${dt.toISOString()}:${mins}`;if(now>=trigger&&now<=dt.getTime()+15*60000&&e.lastReminderKey!==key){e.lastReminderKey=key;const when=mins>=1440?'mañana':mins>=60?`en ${Math.round(mins/60)} h`:`en ${mins} min`;const title=`${eventIcon(e.type)} ${e.title}`;const body=`${e.typeLabel||eventTypeLabel(e.type)} ${when}${e.time?` · ${e.time}`:''}`;state.notifications.unshift({id:uid(),type:'agenda-reminder',title,body,category:'agenda',entityId:e.id,actorId:'system',actorName:'Agenda',createdAt:new Date().toISOString(),readBy:[]});state.activity.unshift({id:uid(),type:'agenda-reminder',title,body,category:'agenda',entityId:e.id,actorId:'system',actorName:'Agenda',createdAt:new Date().toISOString()});changed=true;notifyBrowser(title,body,`agenda-${key}`)}}
  if(changed)persist();else updateNotificationBadge()
}
function eventTypeLabel(t){return({medical:'Cita médica',outing:'Salida',payment:'Pago',family:'Familia',work:'Trabajo',other:'Evento'})[t]||'Evento'}
function addSystemNotification(key,title,body,category){if(state.notificationMeta[key])return false;state.notificationMeta[key]=new Date().toISOString();state.notifications.unshift({id:uid(),type:key,title,body,category,actorId:'system',actorName:'Nuestro Espacio',createdAt:new Date().toISOString(),readBy:[]});state.activity.unshift({id:uid(),type:key,title,body,category,actorId:'system',actorName:'Nuestro Espacio',createdAt:new Date().toISOString()});notifyBrowser(title,body,key);return true}
function checkSmartNotifications(){if(!prefs().enabled)return;const now=new Date(),ym=today().slice(0,7),day=now.getDate();let changed=false;
  if(prefs().finance!==false){const f=financeProjection();if(f.available<0)changed=addSystemNotification(`budget-negative-${ym}`,`⚠️ Presupuesto del mes por cubrir`,`Tus compromisos superan los ingresos programados por ${money(Math.abs(f.available))}.`,'finance')||changed;for(const pay of state.salaryPayments.filter(x=>x.active!==false&&num(x.day)===day))changed=addSystemNotification(`salary-${ym}-${pay.id}`,`💰 Hoy recibes ${pay.name}`,`Ingreso programado: ${money(pay.amount)}.`,'finance')||changed}
  if(prefs().market!==false){const t=marketTotals(),current=t[state.preferredStore];if(num(state.budget)>0&&current>num(state.budget))changed=addSystemNotification(`market-over-${ym}`,`🛒 Mercado sobre el presupuesto`,`La lista pendiente excede el presupuesto por ${money(current-num(state.budget))}.`,'market')||changed}
  if(prefs().pantry!==false){for(const p of state.pantry.filter(x=>num(x.qty)<=num(x.minQty))){const k=`pantry-low-${p.id}-${num(p.qty)}`;changed=addSystemNotification(k,`${p.name} necesita reposición`,`Quedan ${p.qty} ${p.pantryUnit||p.unit}; mínimo ${p.minQty} ${p.pantryUnit||p.unit}.`,'pantry')||changed}}
  const pr=prefs();if(pr.dailySummary){const hhmm=now.toTimeString().slice(0,5);if(hhmm===pr.dailySummaryTime){const low=state.pantry.filter(x=>num(x.qty)<=num(x.minQty)).length,pending=state.shopping.filter(x=>!x.done).length,f=financeProjection();changed=addSystemNotification(`daily-${today()}`,`☀️ Resumen de tu hogar`,`Disponible proyectado ${money(f.available)} · ${pending} compras pendientes · ${low} productos por reponer.`,'shared')||changed}}
  if(changed)persist()
}

