function notificationSettings(){const p=prefs(),permission=('Notification'in window)?Notification.permission:'no compatible',standalone=isStandalone();openSheet('Configurar avisos',`<div class="card permission-card"><small>AVISOS DEL DISPOSITIVO</small><h3>${permission==='granted'?'Activados':permission==='denied'?'Bloqueados':permission==='no compatible'?'No compatibles':'Opcionales'}</h3><p class="muted">La cronología, las alertas compartidas y los recordatorios dentro de la app funcionan sin configurar Web Push. Los avisos del sistema solo se muestran cuando iOS los permite.</p><div class="status-stack"><span class="status-chip ok">✓ Actividad compartida activa</span><span class="status-chip ok">✓ Agenda y recordatorios internos activos</span><span class="status-chip ${standalone?'ok':'warn'}">${standalone?'✓ PWA instalada':'! Abre la app desde su icono para avisos iOS'}</span><span class="status-chip neutral">Push con la app cerrada: en espera</span></div><button class="primary" id="requestNotificationPermission">Activar avisos del sistema</button></div><form class="form prefs-form" id="notificationPrefsForm">${[['enabled','Centro de avisos'],['shared','Actividad compartida'],['agenda','Agenda y citas'],['market','Mercado'],['pantry','Despensa'],['finance','Finanzas']].map(([k,l])=>`<label class="switch-row"><span>${l}</span><input type="checkbox" name="${k}" ${p[k]!==false?'checked':''}></label>`).join('')}<label class="switch-row"><span>Resumen diario</span><input type="checkbox" name="dailySummary" ${p.dailySummary?'checked':''}></label><label>Hora del resumen<input type="time" name="dailySummaryTime" value="${p.dailySummaryTime||'08:00'}"></label><button class="primary">Guardar preferencias</button></form>`);$('requestNotificationPermission').onclick=requestNotifications;$('notificationPrefsForm').onsubmit=e=>{e.preventDefault();const f=new FormData(e.currentTarget),np={...p,dailySummaryTime:f.get('dailySummaryTime')||'08:00'};for(const k of ['enabled','shared','agenda','market','pantry','finance','dailySummary'])np[k]=f.has(k);state.notificationPrefs=np;closeSheet();persist();toast('Preferencias guardadas')}}
function activityCenter(){openSheet('Actividad del hogar',`<div class="list activity-list">${state.activity.slice(0,150).map(a=>`<div class="activity-item"><div class="activity-icon">${a.type==='purchase'?'🛒':a.type==='pantry'?'▥':a.type==='agenda'||a.type==='agenda-reminder'?'📅':a.type==='task'?'✓':'•'}</div><div><small>${a.actorName||'Nuestro Espacio'} · ${new Date(a.createdAt).toLocaleString('es-PE',{dateStyle:'short',timeStyle:'short'})}</small><h3>${a.title}</h3><p>${a.body||''}</p></div></div>`).join('')||'<div class="card empty">Todavía no hay actividad registrada.</div>'}</div>`)}

function show(el,on=true){el.hidden=!on}function setLoading(t){$('loadingText').textContent=t;show($('loading'),true);show($('auth'),false);show($('setup'),false);show($('app'),false)}
function openApp(){show($('loading'),false);show($('auth'),false);show($('setup'),false);show($('app'),true);applyTheme();render()}
function stateEmpty(s){return !s.shopping.length&&!s.tasks.length&&!s.expenses.length&&!s.pantry.length&&!s.notes.length}
async function connect(profile){
  householdId=profile.householdId;inviteCode=profile.inviteCode||'';setLoading('Cargando datos compartidos…');if(unsub)unsub();let first=true,opened=false;
  const rescue=setTimeout(()=>{if(!opened){state=localLoad();openApp();sync('error');toast('La nube está tardando. Mostramos tu copia local.')}},12000);
  unsub=onSnapshot(stateRef(),{includeMetadataChanges:true},async snap=>{
    try{
      if(snap.exists()&&snap.data().state){remote=true;state=migrate(snap.data().state);remote=false;localStorage.setItem('nuestroEspacioPro',JSON.stringify(state));}
      else if(first){const local=localLoad();state=local;if(!stateEmpty(local))await push();else await setDoc(stateRef(),{state,version:VERSION,updatedAt:serverTimestamp()});}
      first=false;opened=true;clearTimeout(rescue);openApp();sync(snap.metadata.hasPendingWrites?'saving':'ok');deliverRemoteNotifications();checkAgendaReminders();checkSmartNotifications();
    }catch(e){console.error('Error procesando datos del hogar',e);opened=true;clearTimeout(rescue);state=localLoad();openApp();sync('error');toast('Abrimos tu copia local; tus datos siguen seguros')}
  },error=>{
    console.error('Error escuchando Firestore',error);opened=true;clearTimeout(rescue);state=localLoad();openApp();sync('error');toast('Sin conexión a Firebase. Usando datos locales.')
  });
}
async function authenticated(u){
  user=u;setLoading('Buscando tu hogar…');
  try{
    const p=await Promise.race([
      getDoc(doc(db,'users',u.uid)),
      new Promise((_,reject)=>setTimeout(()=>reject(new Error('Tiempo de espera agotado al consultar el perfil')),12000))
    ]);
    if(p.exists()&&p.data().householdId)return connect(p.data());
    show($('loading'),false);show($('setup'),true);show($('auth'),false);
  }catch(error){
    console.error('No se pudo cargar el perfil Firebase',error);
    state=localLoad();openApp();sync('error');
    toast('Firebase tardó demasiado. Abrimos tu copia local.');
  }
}
onAuthStateChanged(auth,u=>{
  if(u) authenticated(u).catch(error=>{console.error(error);state=localLoad();openApp();sync('error')});
  else {show($('loading'),false);show($('auth'),true);show($('setup'),false);show($('app'),false)}
},error=>{
  console.error('Error de Authentication',error);show($('loading'),false);show($('auth'),true);$('authError').textContent='No se pudo conectar con Firebase. Revisa internet y vuelve a intentar.';
});
