$('createHome').onsubmit=async e=>{e.preventDefault();const name=new FormData(e.currentTarget).get('name'),hid=uid(),code=Math.random().toString(36).slice(2,8).toUpperCase(),b=writeBatch(db);b.set(doc(db,'households',hid),{name,createdBy:user.uid,createdAt:serverTimestamp(),inviteCode:code});b.set(doc(db,'households',hid,'members',user.uid),{name:user.displayName||user.email,email:user.email,role:'owner'});b.set(doc(db,'invites',code),{householdId:hid,status:'active',createdBy:user.uid,uses:0});b.set(doc(db,'users',user.uid),{name:user.displayName||user.email,email:user.email,householdId:hid,inviteCode:code},{merge:true});await b.commit();connect({householdId:hid,inviteCode:code})};
$('joinHome').onsubmit=async e=>{e.preventDefault();const code=String(new FormData(e.currentTarget).get('code')).toUpperCase(),i=await getDoc(doc(db,'invites',code));if(!i.exists())return toast('Código no válido');const d=i.data(),b=writeBatch(db);b.set(doc(db,'households',d.householdId,'members',user.uid),{name:user.displayName||user.email,email:user.email,role:'member'});b.set(doc(db,'users',user.uid),{name:user.displayName||user.email,email:user.email,householdId:d.householdId,inviteCode:code},{merge:true});b.update(doc(db,'invites',code),{uses:increment(1)});await b.commit();connect({householdId:d.householdId,inviteCode:code})};
function catalog(){const map=new Map(CATALOG.map(x=>[x.id,x]));state.customCatalog.forEach(x=>map.set(x.id,x));return [...map.values()]}
function price(x){const p=catalog().find(p=>p.id===x.productId);return num(x.unitPrice)||(p?num(p[state.preferredStore]):0)}function pendingMarket(){return state.shopping.filter(x=>!x.done).reduce((s,x)=>s+num(x.qty)*price(x),0)}function monthExpenses(){const ym=today().slice(0,7);return state.expenses.filter(x=>String(x.date||'').startsWith(ym)).reduce((s,x)=>s+num(x.amount),0)}function fixedTotal(){return state.fixedExpenses.filter(x=>x.active!==false).reduce((s,x)=>s+num(x.amount),0)}function incomeTotal(){return state.salaryPayments.filter(x=>x.active!==false).reduce((s,x)=>s+num(x.amount),0)+state.extraIncomes.filter(x=>String(x.date||'').startsWith(today().slice(0,7))).reduce((s,x)=>s+num(x.amount),0)}

const STORE_LABELS={market:'Mercado',supermarket:'Supermercado',wholesale:'Mayorista'};
function productRecord(x){return catalog().find(p=>p.id===x.productId)||catalog().find(p=>norm(p.name)===norm(x.title||x.name))||null}
function productEmoji(x){const n=norm(x?.title||x?.name||''),c=norm(x?.category||productRecord(x)?.category||'');const rules=[['sandia','🍉'],['melon','🍈'],['platano','🍌'],['banana','🍌'],['manzana','🍎'],['pera','🍐'],['naranja','🍊'],['mandarina','🍊'],['limon','🍋'],['uva','🍇'],['fresa','🍓'],['arandano','🫐'],['mango','🥭'],['pina','🍍'],['palta','🥑'],['tomate','🍅'],['papa','🥔'],['zanahoria','🥕'],['cebolla','🧅'],['ajo','🧄'],['brocoli','🥦'],['lechuga','🥬'],['pepino','🥒'],['aji','🌶️'],['rocoto','🌶️'],['arroz','🍚'],['pan','🍞'],['huevo','🥚'],['leche','🥛'],['queso','🧀'],['pollo','🍗'],['carne','🥩'],['pescado','🐟'],['atun','🐟'],['agua','💧'],['gaseosa','🥤'],['jugo','🧃'],['cafe','☕'],['chocolate','🍫'],['galleta','🍪'],['caramelo','🍬'],['helado','🍨'],['detergente','🧴'],['jabon','🧼'],['papel','🧻'],['olla','🍲'],['sarten','🍳'],['cuchillo','🔪'],['mascota','🐾']];for(const [k,e] of rules)if(n.includes(k))return e;if(c.includes('fruta'))return'🍎';if(c.includes('verdura'))return'🥬';if(c.includes('carne')||c.includes('pescado'))return'🥩';if(c.includes('lacteo'))return'🥛';if(c.includes('limpieza'))return'🧼';if(c.includes('dulce')||c.includes('snack'))return'🍪';if(c.includes('hogar')||c.includes('cocina'))return'🏠';return'🛒'}
function productImage(x){const e=productEmoji(x),name=String(x?.title||x?.name||'Producto').replace(/[<>&\"']/g,'');const palette=['#E8F3FF','#FFF1E7','#EAF8EE','#F4ECFF','#FFF6D9'];let h=0;for(const ch of name)h=(h+ch.charCodeAt(0))%palette.length;const svg=`<svg xmlns="http://www.w3.org/2000/svg" width="180" height="180" viewBox="0 0 180 180"><rect width="180" height="180" rx="42" fill="${palette[h]}"/><circle cx="90" cy="78" r="52" fill="white" fill-opacity=".72"/><text x="90" y="100" font-size="72" text-anchor="middle">${e}</text><text x="90" y="153" font-family="-apple-system,Arial" font-size="14" font-weight="700" text-anchor="middle" fill="#344054">${name.slice(0,18)}</text></svg>`;return'data:image/svg+xml;charset=UTF-8,'+encodeURIComponent(svg)}
function marketTotals(){const rows=state.shopping.filter(x=>!x.done);const totals={market:0,supermarket:0,wholesale:0,min:0,max:0,count:rows.length};for(const x of rows){const p=productRecord(x),q=num(x.qty);for(const k of ['market','supermarket','wholesale'])totals[k]+=q*(p?num(p[k]):price(x));const probable=q*price(x),mn=p?num(p.minFactor)||.85:.85,mx=p?num(p.maxFactor)||1.18:1.18;totals.min+=probable*mn;totals.max+=probable*mx}return totals}
function financeProjection(){const income=incomeTotal(),fixed=fixedTotal(),spent=monthExpenses(),market=pendingMarket(),available=income-fixed-spent-market;return{income,fixed,spent,market,available,commitments:fixed+spent+market}}
function nextSalary(){const d=new Date(),day=d.getDate(),active=state.salaryPayments.filter(x=>x.active!==false).sort((a,b)=>num(a.day)-num(b.day));let p=active.find(x=>num(x.day)>=day);let monthShift=0;if(!p){p=active[0];monthShift=1}if(!p)return null;const date=new Date(d.getFullYear(),d.getMonth()+monthShift,Math.min(num(p.day),new Date(d.getFullYear(),d.getMonth()+monthShift+1,0).getDate()));return{...p,date,days:Math.max(0,Math.ceil((date-d)/86400000))}}
function compareSheet(id){const x=state.shopping.find(v=>v.id===id);if(!x)return;const p=productRecord(x);if(!p)return toast('Este producto aún no tiene precios de catálogo');const q=num(x.qty);openSheet('Comparar precios',`<div class="product-detail"><img src="${productImage(x)}" alt="${x.title}"><div><small>${p.category||'Producto'}</small><h2>${x.title}</h2><p>${q} ${x.unit}</p></div></div><div class="compare-list">${['market','supermarket','wholesale'].map(k=>`<button class="compare-row ${state.preferredStore===k?'best-active':''}" data-use-store="${k}"><span><small>${STORE_LABELS[k]}</small><b>${money(num(p[k]))} / ${p.unit}</b></span><strong>${money(q*num(p[k]))}</strong></button>`).join('')}</div><div class="range-card"><span>Rango referencial</span><b>${money(q*num(p.market)*(num(p.minFactor)||.85))} – ${money(q*num(p.supermarket)*(num(p.maxFactor)||1.18))}</b></div>`);document.querySelectorAll('[data-use-store]').forEach(b=>b.onclick=()=>{state.preferredStore=b.dataset.useStore;x.unitPrice=num(p[b.dataset.useStore]);closeSheet();persist();toast('Precio actualizado')})}

function safe(module,fn){try{return fn()}catch(e){console.error(module,e);return `<div class="card error-card"><h3>No se pudo mostrar ${module}</h3><p class="muted">Tus datos siguen seguros.</p><button class="primary" onclick="location.reload()">Reintentar</button></div>`}}
const titles={home:'Mi Hogar',market:'Mercado',pantry:'Despensa',agenda:'Agenda',more:'Más'};function go(v){currentView=v;$('pageTitle').textContent=titles[v];document.querySelectorAll('#nav button').forEach(b=>b.classList.toggle('active',b.dataset.view===v));render()}$('nav').onclick=e=>{const b=e.target.closest('button[data-view]');if(b)go(b.dataset.view)};
function render(){if(!$('app')||$('app').hidden)return;$('view').innerHTML=safe(currentView,()=>({home:homeView,market:marketView,pantry:pantryView,agenda:agendaView,more:moreView}[currentView])());bindView();updateNotificationBadge()}
function homeView(){const f=financeProjection(),low=state.pantry.filter(x=>num(x.qty)<=num(x.minQty)).length,next=nextSalary(),pct=f.income?Math.min(100,f.commitments/f.income*100):0;return `<section class="hero finance-hero ${f.available<0?'negative':''}"><small>PROYECCIÓN DEL MES</small><strong>${money(f.available)}</strong><span>${f.available>=0?'Disponible después de compromisos':'Falta por cubrir con los ingresos programados'}</span><div class="hero-progress"><span style="width:${pct}%"></span></div><div class="hero-foot"><span>${Math.round(pct)}% comprometido</span><span>${next?`Próximo ingreso: ${next.name} en ${next.days} días`:'Configura tus ingresos'}</span></div></section><div class="projection-grid"><div><small>Ingresos</small><b>${money(f.income)}</b></div><div><small>Gastos fijos</small><b>${money(f.fixed)}</b></div><div><small>Ya gastado</small><b>${money(f.spent)}</b></div><div><small>Mercado pendiente</small><b>${money(f.market)}</b></div></div><div class="grid"><button class="card metric" data-go="market"><small>Mercado</small><b>${state.shopping.filter(x=>!x.done).length}</b><span class="muted">pendientes · ${money(f.market)}</span></button><button class="card metric" data-go="pantry"><small>Despensa</small><b>${low}</b><span class="muted">por reponer</span></button><div class="card metric"><small>Tareas</small><b>${state.tasks.filter(x=>!x.done).length}</b><span class="muted">pendientes</span></div><button class="card metric" data-open="finance"><small>Proyección</small><b>${f.available>=0?'✓':'!'}</b><span class="muted">ver detalle mensual</span></button></div><div class="section-head"><h2>Atención hoy</h2></div><div class="list">${state.pantry.filter(x=>num(x.qty)<=num(x.minQty)).slice(0,3).map(pantryCard).join('')||'<div class="card empty">Todo en orden en la despensa.</div>'}</div>`}
function marketView(){let a=state.shopping.filter(x=>marketFilter==='all'||marketFilter==='done'?x.done:marketFilter==='pending'?!x.done:state.favorites.includes(x.productId));if(marketSearch)a=a.filter(x=>norm(x.title).includes(norm(marketSearch)));const t=marketTotals(),current=t[state.preferredStore],balance=num(state.budget)-current,best=[['market',t.market],['supermarket',t.supermarket],['wholesale',t.wholesale]].sort((a,b)=>a[1]-b[1])[0];return `<section class="market-hero"><div><small>PRESUPUESTO DEL MERCADO</small><strong>${money(state.budget)}</strong><span class="${balance<0?'bad':'good'}">${balance>=0?`Te quedarían ${money(balance)}`:`Excede por ${money(Math.abs(balance))}`}</span></div><div class="market-ring"><b>${t.count}</b><small>productos</small></div></section><div class="estimate-strip"><div><small>Mínimo</small><b>${money(t.min)}</b></div><div class="primary-est"><small>Probable · ${STORE_LABELS[state.preferredStore]}</small><b>${money(current)}</b></div><div><small>Máximo</small><b>${money(t.max)}</b></div></div><div class="store-comparison"><div class="section-head compact"><h2>Comparación por lugar</h2><span class="best-chip">Mejor estimado: ${STORE_LABELS[best[0]]}</span></div><div class="store-cards">${[['market','Mercado'],['supermarket','Supermercado'],['wholesale','Mayorista']].map(([k,l])=>`<button data-store="${k}" class="store-card ${state.preferredStore===k?'active':''}"><small>${l}</small><b>${money(t[k])}</b><span>${t.count?money(t[k]/t.count):money(0)} prom./producto</span></button>`).join('')}</div></div><div class="search">⌕<input id="marketSearch" value="${marketSearch}" placeholder="Buscar en tu lista"></div><div class="segments" id="marketFilters"><button data-filter="pending" class="${marketFilter==='pending'?'active':''}">Pendientes</button><button data-filter="favorites" class="${marketFilter==='favorites'?'active':''}">Favoritos</button><button data-filter="done" class="${marketFilter==='done'?'active':''}">Comprados</button><button data-filter="all" class="${marketFilter==='all'?'active':''}">Todos</button></div><div class="list product-list">${a.map(marketCard).join('')||'<div class="card empty">No hay productos en este filtro.</div>'}</div>`}
function marketCard(x){const p=productRecord(x),unit=price(x),total=num(x.qty)*unit;return `<div class="product-card ${x.done?'is-done':''}"><button class="check ${x.done?'done':''}" data-toggle-shop="${x.id}">${x.done?'✓':''}</button><img class="product-thumb" src="${productImage(x)}" alt="${x.title}"><div class="product-main"><div class="product-title"><h3>${x.title}</h3>${p?`<span>${p.category||''}</span>`:''}</div><p>${x.qty} ${x.unit} · ${money(unit)} por ${x.unit}</p><div class="product-price"><b>${money(total)}</b>${p?`<button data-compare-shop="${x.id}">Comparar</button>`:''}</div></div><button class="pill-btn" data-edit-shop="${x.id}">•••</button></div>`}
function pantryView(){const q=window.__pantryQ||'',a=state.pantry.filter(x=>(!q||norm(x.name).includes(norm(q)))&&(pantryFilter==='all'||pantryFilter==='low'&&num(x.qty)<=num(x.minQty)||pantryFilter==='stock'&&num(x.qty)>num(x.minQty)));return `<div class="section-head"><div><h2>Despensa</h2><p class="muted">Existencias, consumo y reposición.</p></div><button class="pill-btn" data-new-pantry>＋ Producto</button></div><div class="kpis"><div class="kpi"><small>Productos</small><b>${state.pantry.length}</b></div><div class="kpi"><small>Por reponer</small><b>${state.pantry.filter(x=>num(x.qty)<=num(x.minQty)).length}</b></div><div class="kpi"><small>Vence pronto</small><b>${state.pantry.filter(x=>x.expiry&&((new Date(x.expiry)-new Date())/86400000)<=7).length}</b></div></div><div class="search">⌕<input id="pantrySearch" value="${q}" placeholder="Buscar en la despensa"></div><div class="segments" id="pantryFilters"><button data-filter="all" class="${pantryFilter==='all'?'active':''}">Todos</button><button data-filter="low" class="${pantryFilter==='low'?'active':''}">Por reponer</button><button data-filter="stock" class="${pantryFilter==='stock'?'active':''}">En stock</button></div><div class="list">${a.map(pantryCard).join('')||'<div class="card empty">No hay productos para mostrar.</div>'}</div>`}
function pantryCard(x){const max=Math.max(num(x.minQty)*2,1),pct=Math.min(100,num(x.qty)/max*100),low=num(x.qty)<=num(x.minQty),days=num(x.dailyUse)>0?Math.floor(num(x.qty)/num(x.dailyUse)):null;return `<div class="card pantry-card"><div class="pantry-top"><img class="product-thumb large" src="${productImage(x)}" alt="${x.name}"><div class="main"><h3>${x.name}</h3><p>${x.qty} ${x.pantryUnit||x.unit||'unidad'} · mínimo ${x.minQty||0}</p><span class="stock-chip ${low?'low':'ok'}">${low?'Reponer':'En stock'}</span></div><button class="pill-btn" data-edit-pantry="${x.id}">Editar</button></div><div class="bar ${low?'low':''}"><span style="width:${pct}%"></span></div><div class="pantry-meta"><span>${days!==null?`Dura aprox. ${days} días`:(low?'Requiere reposición':'Stock suficiente')}</span><b>${Math.round(pct)}%</b></div><div class="actions"><button data-consume="${x.id}">Consumir</button><button data-restock="${x.id}">Comprar</button></div></div>`}
function agendaView(){const a=[...state.events].sort((x,y)=>String(x.date||'').localeCompare(String(y.date||''))||String(x.time||'').localeCompare(String(y.time||'')));return `<div class="section-head"><div><h2>Agenda</h2><p class="muted">Citas médicas, salidas, pagos y compromisos con recordatorios.</p></div><button class="pill-btn" data-new-event>＋ Evento</button></div><div class="agenda-summary card"><div><small>PRÓXIMOS 7 DÍAS</small><b>${a.filter(e=>{const d=eventDateTime(e);return d&&d>=new Date()&&d-new Date()<=7*86400000}).length}</b></div><button class="pill-btn" data-open="notifications">Ver avisos</button></div><div class="list">${a.map(x=>`<div class="row-card agenda-card"><div class="icon">${eventIcon(x.type)}</div><div class="main"><div class="event-title-line"><h3>${x.title}</h3><span>${eventTypeLabel(x.type)}</span></div><p>${x.date||'Sin fecha'} ${x.time||''}</p><small class="muted">Recordatorio: ${num(x.reminderMinutes??60)>=1440?'1 día antes':num(x.reminderMinutes??60)>=60?`${Math.round(num(x.reminderMinutes??60)/60)} h antes`:`${num(x.reminderMinutes??60)} min antes`} · ${x.notifyAll===false?'Solo yo':'Compartido'}</small></div><button class="pill-btn" data-edit-event="${x.id}">Editar</button></div>`).join('')||'<div class="card empty">No tienes eventos próximos.</div>'}</div>`}
function moreView(){return `<div class="list"><button class="row-card" data-open="notifications"><div class="icon">🔔</div><div class="main"><h3>Notificaciones</h3><p>${unreadNotifications()} sin leer · agenda y actividad compartida</p></div></button><button class="row-card" data-open="activity"><div class="icon">◷</div><div class="main"><h3>Actividad del hogar</h3><p>Quién agregó, compró o actualizó algo</p></div></button><button class="row-card" data-open="notificationSettings"><div class="icon">⚙</div><div class="main"><h3>Configurar avisos</h3><p>Agenda, mercado, despensa y finanzas</p></div></button><button class="row-card" data-open="tasks"><div class="icon">✓</div><div class="main"><h3>Tareas</h3><p>${state.tasks.length} registradas</p></div></button><button class="row-card" data-open="finance"><div class="icon">S/</div><div class="main"><h3>Finanzas</h3><p>Ingresos, gastos y presupuesto</p></div></button><button class="row-card" data-open="account"><div class="icon">☁</div><div class="main"><h3>Cuenta y sincronización</h3><p>Código ${inviteCode||'—'}</p></div></button><button class="row-card" data-open="backup"><div class="icon">⇩</div><div class="main"><h3>Exportar respaldo</h3><p>Copia JSON de tus datos</p></div></button><div class="card"><small>VERSIÓN ACTUAL</small><h2>v${VERSION}</h2><p class="muted">Versión estable · Firebase · avisos internos activos</p></div></div>`}
function bindView(){document.querySelectorAll('[data-go]').forEach(b=>b.onclick=()=>go(b.dataset.go));$('marketSearch')?.addEventListener('input',e=>{marketSearch=e.target.value;render()});$('marketFilters')?.addEventListener('click',e=>{const b=e.target.closest('button');if(b){marketFilter=b.dataset.filter;render()}});$('storeSeg')?.addEventListener('click',e=>{const b=e.target.closest('button');if(b){state.preferredStore=b.dataset.store;persist()}});$('pantrySearch')?.addEventListener('input',e=>{window.__pantryQ=e.target.value;render()});$('pantryFilters')?.addEventListener('click',e=>{const b=e.target.closest('button');if(b){pantryFilter=b.dataset.filter;render()}});document.querySelectorAll('[data-toggle-shop]').forEach(b=>b.onclick=()=>toggleShop(b.dataset.toggleShop));document.querySelectorAll('[data-edit-shop]').forEach(b=>b.onclick=()=>shopForm(b.dataset.editShop));document.querySelectorAll('[data-compare-shop]').forEach(b=>b.onclick=()=>compareSheet(b.dataset.compareShop));document.querySelectorAll('[data-new-pantry]').forEach(b=>b.onclick=()=>pantryForm());document.querySelectorAll('[data-edit-pantry]').forEach(b=>b.onclick=()=>pantryForm(b.dataset.editPantry));document.querySelectorAll('[data-consume]').forEach(b=>b.onclick=()=>consumeForm(b.dataset.consume));document.querySelectorAll('[data-restock]').forEach(b=>b.onclick=()=>restock(b.dataset.restock));document.querySelectorAll('[data-new-event]').forEach(b=>b.onclick=()=>eventForm());document.querySelectorAll('[data-edit-event]').forEach(b=>b.onclick=()=>eventForm(b.dataset.editEvent));document.querySelectorAll('[data-open]').forEach(b=>b.onclick=()=>moreAction(b.dataset.open))}
function openSheet(title,html){$('sheetTitle').textContent=title;$('sheetBody').innerHTML=html;show($('sheet'),true);document.body.style.overflow='hidden'}function closeSheet(){show($('sheet'),false);document.body.style.overflow=''}$('sheetClose').onclick=closeSheet;$('sheet').onclick=e=>{if(e.target===$('sheet'))closeSheet()};
const units=['kg','g','litro','ml','unidad','unidades','docena','bolsa','paquete','botella','lata','frasco','caja','porciones'];function opts(sel){return units.map(u=>`<option ${u===sel?'selected':''}>${u}</option>`).join('')}
function shopForm(id=''){
  const x=state.shopping.find(x=>x.id===id)||{id:'',title:'',qty:1,unit:'unidad',unitPrice:0,category:'Otros',productId:''};
  const initial=catalog().find(p=>p.id===x.productId)||catalog().find(p=>norm(p.name)===norm(x.title));
  const suggested=initial?num(initial[state.preferredStore]):num(x.unitPrice);
  openSheet(id?'Editar compra':'Nueva compra',`<form class="form" id="sf">
    <input type="hidden" name="id" value="${x.id}">
    <input type="hidden" name="productId" id="sfProductId" value="${x.productId||initial?.id||''}">
    <label>Producto
      <input name="title" id="sfTitle" value="${x.title}" required autocomplete="off" placeholder="Ej. tomate, arroz, leche">
    </label>
    <div id="catalogSuggest" class="catalog-suggest" hidden></div>
    <div id="pricePreview" class="price-preview"></div>
    <div class="two">
      <label>Cantidad<input name="qty" id="sfQty" type="number" step=".01" min="0.01" value="${x.qty}" required></label>
      <label>Unidad<select name="unit" id="sfUnit">${opts(x.unit||initial?.unit||'unidad')}</select></label>
    </div>
    <label>Precio por unidad
      <div class="money-input"><span>S/</span><input name="unitPrice" id="sfUnitPrice" type="number" min="0" step=".01" value="${(num(x.unitPrice)||suggested||0).toFixed(2)}"></div>
      <small class="muted">Puedes editarlo si el precio real es distinto.</small>
    </label>
    <div class="form-total" id="sfTotal"></div>
    <button class="primary">Guardar</button>
    ${id?'<button type="button" class="primary danger" id="delShop">Eliminar</button>':''}
  </form>`);

  const title=$('sfTitle'), unit=$('sfUnit'), unitPrice=$('sfUnitPrice'), productId=$('sfProductId'), suggest=$('catalogSuggest'), preview=$('pricePreview'), qty=$('sfQty'), total=$('sfTotal');
  let selected=initial||null;

  function storeLabel(k){return k==='market'?'Mercado':k==='supermarket'?'Supermercado':'Mayorista'}
  function renderPreview(p){
    if(!p){preview.innerHTML='<div class="catalog-empty">Producto sin precio del catálogo. Ingresa el precio manualmente.</div>';return}
    preview.innerHTML=`<div class="price-preview-head"><div><b>${p.name}</b><small>${p.category||'Producto'} · por ${p.unit||'unidad'}</small></div><span class="price-badge">${storeLabel(state.preferredStore)}</span></div><div class="price-grid"><button type="button" data-pick-price="market"><small>Mercado</small><b>${money(p.market)}</b></button><button type="button" data-pick-price="supermarket"><small>Supermercado</small><b>${money(p.supermarket)}</b></button><button type="button" data-pick-price="wholesale"><small>Mayorista</small><b>${money(p.wholesale)}</b></button></div>`;
    preview.querySelectorAll('[data-pick-price]').forEach(b=>b.onclick=()=>{const k=b.dataset.pickPrice;unitPrice.value=num(p[k]).toFixed(2);updateTotal();preview.querySelectorAll('button').forEach(x=>x.classList.toggle('active',x===b))});
    const active=preview.querySelector(`[data-pick-price="${state.preferredStore}"]`);if(active)active.classList.add('active');
  }
  function choose(p){selected=p;title.value=p.name;productId.value=p.id;unit.value=p.unit||'unidad';unitPrice.value=num(p[state.preferredStore]).toFixed(2);suggest.hidden=true;renderPreview(p);updateTotal()}
  function showSuggestions(){
    const q=norm(title.value);if(!q){suggest.hidden=true;return}
    const matches=catalog().filter(p=>norm(p.name).includes(q)).slice(0,8);
    if(!matches.length){suggest.hidden=true;return}
    suggest.innerHTML=matches.map(p=>`<button type="button" data-catalog-id="${p.id}"><span><b>${p.name}</b><small>${p.category||''} · ${p.unit||'unidad'}</small></span><strong>${money(p[state.preferredStore])}</strong></button>`).join('');
    suggest.hidden=false;suggest.querySelectorAll('[data-catalog-id]').forEach(b=>b.onclick=()=>choose(catalog().find(p=>p.id===b.dataset.catalogId)));
  }
  function detectExact(){const p=catalog().find(p=>norm(p.name)===norm(title.value));if(p){choose(p)}else{selected=null;productId.value='';renderPreview(null);updateTotal()}}
  function updateTotal(){total.innerHTML=`<span>Subtotal estimado</span><strong>${money(num(qty.value)*num(unitPrice.value))}</strong>`}

  title.addEventListener('input',()=>{selected=null;productId.value='';showSuggestions()});
  title.addEventListener('change',detectExact);
  title.addEventListener('blur',()=>setTimeout(()=>{suggest.hidden=true;detectExact()},180));
  qty.addEventListener('input',updateTotal);unitPrice.addEventListener('input',updateTotal);
  renderPreview(initial||null);updateTotal();

  $('sf').onsubmit=e=>{
    e.preventDefault();const o=Object.fromEntries(new FormData(e.currentTarget));o.qty=num(o.qty);o.unitPrice=num(o.unitPrice);
    const p=catalog().find(p=>p.id===o.productId)||catalog().find(p=>norm(p.name)===norm(o.title));
    if(p){o.productId=p.id;o.title=p.name;o.unit=o.unit||p.unit;o.category=p.category||x.category||'Otros';if(!o.unitPrice)o.unitPrice=num(p[state.preferredStore])}
    else{o.productId=x.productId||'';o.category=x.category||'Otros'}
    o.done=x.done||false;if(id){Object.assign(x,o);addActivity('market',`Actualizó ${o.title}`,`${o.qty} ${o.unit}`,'shared',x.id)}else{o.id=uid();state.shopping.unshift(o);addActivity('market',`Agregó ${o.title} al mercado`,`${o.qty} ${o.unit}`,'shared',o.id)}closeSheet();persist()
  };
  $('delShop')?.addEventListener('click',()=>{const item=state.shopping.find(v=>v.id===id);state.shopping=state.shopping.filter(v=>v.id!==id);if(item)addActivity('market',`Eliminó ${item.title} del mercado`,'','shared',id);closeSheet();persist()})
}
function toggleShop(id){const x=state.shopping.find(x=>x.id===id);if(!x)return;if(!x.done)return completePurchase(x);rollbackPurchase(x);persist()}
function completePurchase(x){openSheet('Confirmar compra',`<form class="form" id="complete"><p>${x.title} · ${x.qty} ${x.unit}</p><label>Total pagado<input name="amount" type="number" step=".01" value="${(x.qty*price(x)).toFixed(2)}"></label><label>Cantidad a despensa<input name="pantryQty" type="number" step=".01" value="${x.qty}"></label><label>Unidad de despensa<select name="pantryUnit">${opts(x.pantryUnit||x.unit)}</select></label><button class="primary">Guardar compra</button></form>`);$('complete').onsubmit=e=>{e.preventDefault();const o=Object.fromEntries(new FormData(e.currentTarget)),eid=uid();x.done=true;x.actualTotal=num(o.amount);x.purchaseDate=today();x.linkedExpenseId=eid;x.pantryAddQty=num(o.pantryQty);x.pantryUnit=o.pantryUnit;state.expenses.unshift({id:eid,sourcePurchaseId:x.id,title:'Mercado: '+x.title,amount:x.actualTotal,date:today(),category:'Mercado'});let p=state.pantry.find(p=>norm(p.name)===norm(x.title));if(!p){p={id:uid(),name:x.title,qty:0,minQty:0,unit:x.pantryUnit,pantryUnit:x.pantryUnit,purchaseUnit:x.unit,conversionRate:x.qty?x.pantryAddQty/x.qty:1};state.pantry.unshift(p)}p.qty=num(p.qty)+x.pantryAddQty;x.pantryMovement={itemId:p.id,qty:x.pantryAddQty};addActivity('purchase',`Compró ${x.title}`,`${x.pantryAddQty} ${x.pantryUnit} añadidos a despensa · ${money(x.actualTotal)}`,'shared',x.id);closeSheet();persist()}}
function rollbackPurchase(x){x.done=false;if(x.linkedExpenseId)state.expenses=state.expenses.filter(e=>e.id!==x.linkedExpenseId);if(x.pantryMovement){const p=state.pantry.find(p=>p.id===x.pantryMovement.itemId);if(p)p.qty=Math.max(0,num(p.qty)-num(x.pantryMovement.qty))}delete x.linkedExpenseId;delete x.pantryMovement;addActivity('purchase',`Revirtió la compra de ${x.title}`,'Se retiró el gasto y el movimiento de despensa','shared',x.id)}
function pantryForm(id=''){const x=state.pantry.find(x=>x.id===id)||{name:'',qty:0,minQty:0,unit:'unidad',pantryUnit:'unidad',purchaseUnit:'unidad',conversionRate:1,dailyUse:0,expiry:''};openSheet(id?'Editar producto':'Nuevo producto',`<form class="form" id="pf"><label>Producto<input name="name" value="${x.name}" required></label><div class="two"><label>Cantidad<input name="qty" type="number" step=".01" value="${x.qty}"></label><label>Mínimo<input name="minQty" type="number" step=".01" value="${x.minQty}"></label></div><div class="two"><label>Unidad de despensa<select name="pantryUnit">${opts(x.pantryUnit||x.unit)}</select></label><label>Unidad de compra<select name="purchaseUnit">${opts(x.purchaseUnit||x.unit)}</select></label></div><div class="two"><label>Unidades por compra<input name="conversionRate" type="number" step=".01" value="${x.conversionRate||1}"></label><label>Consumo diario<input name="dailyUse" type="number" step=".01" value="${x.dailyUse||0}"></label></div><label>Vencimiento<input name="expiry" type="date" value="${x.expiry||''}"></label><button class="primary">Guardar</button>${id?'<button type="button" class="primary danger" id="delPantry">Eliminar</button>':''}</form>`);$('pf').onsubmit=e=>{e.preventDefault();const o=Object.fromEntries(new FormData(e.currentTarget));['qty','minQty','conversionRate','dailyUse'].forEach(k=>o[k]=num(o[k]));o.unit=o.pantryUnit;if(id){Object.assign(x,o);addActivity('pantry',`Actualizó ${o.name} en despensa`,`${o.qty} ${o.pantryUnit}`,'shared',id)}else{o.id=uid();state.pantry.unshift(o);addActivity('pantry',`Añadió ${o.name} a despensa`,`${o.qty} ${o.pantryUnit}`,'shared',o.id)}closeSheet();persist()};$('delPantry')?.addEventListener('click',()=>{state.pantry=state.pantry.filter(v=>v.id!==id);closeSheet();persist()})}
function consumeForm(id){const x=state.pantry.find(x=>x.id===id);openSheet('Consumir '+x.name,`<form class="form" id="cf"><p>Disponible: <b>${x.qty} ${x.pantryUnit||x.unit}</b></p><label>Cantidad<input name="qty" type="number" step=".01" required></label><label>Unidad<select name="unit">${opts(x.pantryUnit||x.unit)}</select></label><button class="primary">Confirmar consumo</button></form>`);$('cf').onsubmit=e=>{e.preventDefault();const o=Object.fromEntries(new FormData(e.currentTarget));let q=num(o.qty),base=x.pantryUnit||x.unit;if(base==='kg'&&o.unit==='g')q/=1000;if(base==='litro'&&o.unit==='ml')q/=1000;if(q>x.qty)return toast('No hay suficiente stock');x.qty=Math.max(0,x.qty-q);addActivity('pantry',`Consumió ${x.name}`,`${q} ${base} · quedan ${x.qty} ${base}`,'shared',x.id);if(x.qty<=num(x.minQty)&&prefs().pantry!==false){state.notifications.unshift({id:uid(),type:'pantry-low',title:`${x.name} necesita reposición`,body:`Quedan ${x.qty} ${base}; mínimo ${x.minQty} ${base}`,category:'pantry',entityId:x.id,actorId:'system',actorName:'Despensa',createdAt:new Date().toISOString(),readBy:[]})}closeSheet();persist()}}
function restock(id){const x=state.pantry.find(x=>x.id===id),need=Math.max(0,num(x.minQty)-num(x.qty));if(!need)return toast('Stock suficiente');const qty=need/(num(x.conversionRate)||1),e=state.shopping.find(s=>!s.done&&norm(s.title)===norm(x.name));if(e)e.qty+=qty;else state.shopping.unshift({id:uid(),title:x.name,qty,unit:x.purchaseUnit||x.unit,productId:'',unitPrice:0,done:false});addActivity('market',`Añadió ${x.name} al mercado desde despensa`,`${qty.toFixed(2)} ${x.purchaseUnit||x.unit}`,'shared',x.id);persist();toast('Añadido al mercado')}
function eventForm(id=''){const x=state.events.find(e=>e.id===id)||{title:'',date:today(),time:'09:00',type:'medical',reminderMinutes:60,notifyAll:true,notes:''};openSheet(id?'Editar evento':'Nuevo evento',`<form class="form" id="ef"><label>Título<input name="title" value="${x.title||''}" required placeholder="Ej. Control médico"></label><div class="two"><label>Fecha<input name="date" type="date" value="${x.date||today()}" required></label><label>Hora<input name="time" type="time" value="${x.time||'09:00'}"></label></div><label>Tipo<select name="type">${[['medical','Cita médica'],['outing','Salida'],['payment','Pago'],['family','Familia'],['work','Trabajo'],['other','Otro']].map(([v,l])=>`<option value="${v}" ${x.type===v?'selected':''}>${l}</option>`).join('')}</select></label><label>Recordarme<select name="reminderMinutes">${[[0,'A la hora'],[15,'15 minutos antes'],[30,'30 minutos antes'],[60,'1 hora antes'],[120,'2 horas antes'],[1440,'1 día antes'],[2880,'2 días antes']].map(([v,l])=>`<option value="${v}" ${num(x.reminderMinutes??60)===v?'selected':''}>${l}</option>`).join('')}</select></label><label class="switch-row"><span>Notificar a ambos</span><input type="checkbox" name="notifyAll" ${x.notifyAll!==false?'checked':''}></label><label>Notas<textarea name="notes" rows="3" placeholder="Dirección, indicaciones o detalles">${x.notes||''}</textarea></label><button class="primary">Guardar evento</button>${id?'<button type="button" class="primary danger" id="deleteEvent">Eliminar evento</button>':''}</form>`);$('ef').onsubmit=e=>{e.preventDefault();const f=new FormData(e.currentTarget),o=Object.fromEntries(f);o.reminderMinutes=num(o.reminderMinutes);o.notifyAll=f.has('notifyAll');delete o.lastReminderKey;if(id){Object.assign(x,o);addActivity('agenda',`Actualizó: ${o.title}`,`${o.date} ${o.time||''}`,'agenda',id)}else{o.id=uid();state.events.unshift(o);addActivity('agenda',`Agendó: ${o.title}`,`${eventTypeLabel(o.type)} · ${o.date} ${o.time||''}`,'agenda',o.id)}closeSheet();persist();checkAgendaReminders()};$('deleteEvent')?.addEventListener('click',()=>{state.events=state.events.filter(e=>e.id!==id);addActivity('agenda',`Eliminó: ${x.title}`,'','agenda',id);closeSheet();persist()})}
function moreAction(a){if(a==='notifications')return notificationCenter();if(a==='notificationSettings')return notificationSettings();if(a==='activity')return activityCenter();if(a==='backup'){const blob=new Blob([JSON.stringify(state,null,2)],{type:'application/json'}),u=URL.createObjectURL(blob),l=document.createElement('a');l.href=u;l.download='nuestro-espacio-v7.json';l.click();URL.revokeObjectURL(u);return}if(a==='account'){openSheet('Cuenta y sincronización',`<div class="list"><div class="card"><small>USUARIO</small><h3>${user?.displayName||user?.email}</h3></div><div class="card"><small>CÓDIGO DEL HOGAR</small><h2>${inviteCode||'—'}</h2><button class="primary" id="copyCode">Copiar código</button></div><button class="primary danger" id="logout">Cerrar sesión</button></div>`);$('copyCode').onclick=()=>navigator.clipboard.writeText(inviteCode).then(()=>toast('Código copiado'));$('logout').onclick=()=>signOut(auth).then(closeSheet);return}if(a==='finance'){const f=financeProjection(),t=marketTotals(),pct=f.income?Math.min(100,f.commitments/f.income*100):0;openSheet('Proyección financiera',`<section class="finance-sheet-hero ${f.available<0?'negative':''}"><small>SALDO PROYECTADO DEL MES</small><b>${money(f.available)}</b><span>${f.available>=0?'Tus ingresos cubren los compromisos actuales':'Tus compromisos superan los ingresos programados'}</span></section><div class="finance-lines"><div><span>Ingresos programados</span><b>${money(f.income)}</b></div><div><span>Gastos fijos</span><b>− ${money(f.fixed)}</b></div><div><span>Gastos registrados</span><b>− ${money(f.spent)}</b></div><div><span>Mercado pendiente</span><b>− ${money(f.market)}</b></div><div class="total"><span>Disponible proyectado</span><b>${money(f.available)}</b></div></div><div class="card"><div class="section-head compact"><h3>Nivel comprometido</h3><b>${Math.round(pct)}%</b></div><div class="bar ${pct>100?'low':''}"><span style="width:${Math.min(100,pct)}%"></span></div></div><div class="card"><h3>Escenarios de mercado</h3><div class="scenario-grid"><div><small>Mayorista</small><b>${money(t.wholesale)}</b></div><div><small>Mercado</small><b>${money(t.market)}</b></div><div><small>Supermercado</small><b>${money(t.supermarket)}</b></div></div></div>`);return}if(a==='tasks'){openSheet('Tareas',`<form class="form" id="tf"><label>Nueva tarea<input name="title" required></label><button class="primary">Agregar</button></form><div class="list" id="taskList">${state.tasks.map(t=>`<div class="row-card"><button class="check ${t.done?'done':''}" data-task="${t.id}">${t.done?'✓':''}</button><div class="main"><h3>${t.title}</h3></div></div>`).join('')}</div>`);$('tf').onsubmit=e=>{e.preventDefault();const task={id:uid(),title:new FormData(e.currentTarget).get('title'),done:false};state.tasks.unshift(task);addActivity('task',`Agregó la tarea: ${task.title}`,'','shared',task.id);closeSheet();persist()};document.querySelectorAll('[data-task]').forEach(b=>b.onclick=()=>{const t=state.tasks.find(t=>t.id===b.dataset.task);t.done=!t.done;addActivity('task',`${t.done?'Completó':'Reabrió'} la tarea: ${t.title}`,'','shared',t.id);closeSheet();persist()})}}
$('fab').onclick=()=>currentView==='market'?shopForm():currentView==='pantry'?pantryForm():currentView==='agenda'?eventForm():moreAction('tasks');$('themeBtn').onclick=()=>{state.theme=state.theme==='dark'?'light':'dark';applyTheme();persist()};function applyTheme(){document.body.classList.toggle('dark',state.theme==='dark')}$('syncBtn').onclick=push;$('notificationBtn').onclick=notificationCenter;
window.addEventListener('error',event=>{console.error('Error global',event.error||event.message);if(!$('loading').hidden){state=localLoad();openApp();sync('error');toast('Se recuperó el inicio de la app.')}});
window.addEventListener('unhandledrejection',event=>{console.error('Promesa no controlada',event.reason);if(!$('loading').hidden){state=localLoad();openApp();sync('error');toast('Se recuperó el inicio de la app.')}});
setTimeout(()=>{if(!$('loading').hidden){state=localLoad();openApp();sync('error');toast('Inicio recuperado con la copia local.')}},15000);
setInterval(()=>{checkAgendaReminders();checkSmartNotifications()},60000);document.addEventListener('visibilitychange',()=>{if(document.visibilityState==='visible'){checkAgendaReminders();checkSmartNotifications();deliverRemoteNotifications()}});if('serviceWorker'in navigator)navigator.serviceWorker.register('./sw.js');
